# Azure SRE Agent Infrastructure

resource "azurerm_user_assigned_identity" "sre_agent" {
  name                = "${var.sre_agent_name}-identity"
  resource_group_name = data.azurerm_resource_group.main.name
  location            = data.azurerm_resource_group.main.location
  tags = { Environment = "Production", Purpose = "SRE-Agent" }
}

resource "azurerm_role_assignment" "sre_agent_reader" {
  scope                = data.azurerm_resource_group.main.id
  role_definition_name = "Reader"
  principal_id         = azurerm_user_assigned_identity.sre_agent.principal_id
}

resource "azurerm_role_assignment" "sre_agent_monitor_reader" {
  scope                = data.azurerm_resource_group.main.id
  role_definition_name = "Monitoring Reader"
  principal_id         = azurerm_user_assigned_identity.sre_agent.principal_id
}

resource "azurerm_key_vault" "sre_agent" {
  name                       = "${var.sre_agent_name}-kv"
  location                   = data.azurerm_resource_group.main.location
  resource_group_name        = data.azurerm_resource_group.main.name
  tenant_id                  = data.azurerm_client_config.current.tenant_id
  sku_name                   = "standard"
  soft_delete_retention_days = 7
  purge_protection_enabled   = false

  access_policy {
    tenant_id = data.azurerm_client_config.current.tenant_id
    object_id = azurerm_user_assigned_identity.sre_agent.principal_id
    secret_permissions = ["Get", "List"]
  }

  access_policy {
    tenant_id = data.azurerm_client_config.current.tenant_id
    object_id = data.azurerm_client_config.current.object_id
    secret_permissions = ["Get", "List", "Set", "Delete", "Purge"]
  }

  tags = { Environment = "Production", Purpose = "SRE-Agent-Secrets" }
}

resource "azurerm_log_analytics_workspace" "sre_agent" {
  name                = "${var.sre_agent_name}-logs"
  location            = data.azurerm_resource_group.main.location
  resource_group_name = data.azurerm_resource_group.main.name
  sku                 = "PerGB2018"
  retention_in_days   = 30
  tags = { Environment = "Production", Purpose = "SRE-Agent-Telemetry" }
}

resource "azurerm_container_group" "sre_agent" {
  name                = var.sre_agent_name
  location            = data.azurerm_resource_group.main.location
  resource_group_name = data.azurerm_resource_group.main.name
  os_type             = "Linux"
  ip_address_type     = "Private"

  identity {
    type         = "UserAssigned"
    identity_ids = [azurerm_user_assigned_identity.sre_agent.id]
  }

  container {
    name   = "sre-agent"
    image  = var.sre_agent_container_image
    cpu    = "1"
    memory = "2"

    ports {
      port     = 8080
      protocol = "TCP"
    }

    environment_variables = {
      AZURE_TENANT_ID            = data.azurerm_client_config.current.tenant_id
      AZURE_SUBSCRIPTION_ID      = data.azurerm_client_config.current.subscription_id
      KEY_VAULT_URL              = azurerm_key_vault.sre_agent.vault_uri
      KUSTO_CLUSTER_URI          = azurerm_kusto_cluster.main.uri
      KUSTO_DATABASE             = azurerm_kusto_database.main.name
      LOG_ANALYTICS_WORKSPACE_ID = azurerm_log_analytics_workspace.sre_agent.workspace_id
    }
  }

  diagnostics {
    log_analytics {
      workspace_id  = azurerm_log_analytics_workspace.sre_agent.workspace_id
      workspace_key = azurerm_log_analytics_workspace.sre_agent.primary_shared_key
    }
  }

  tags = { Environment = "Production", Purpose = "SRE-Agent" }
}

