# SRE Agent Integration Configuration

# Grant SRE Agent managed identity write access to Kusto
resource "azurerm_kusto_database_principal_assignment" "sre_agent_ingestor" {
  resource_group_name = data.azurerm_resource_group.main.name
  cluster_name        = azurerm_kusto_cluster.main.name
  database_name       = azurerm_kusto_database.main.name
  name                = "sre-agent-ingestor"
  principal_id        = azurerm_user_assigned_identity.sre_agent.principal_id
  principal_type      = "App"
  role                = "Ingestor"
  tenant_id           = data.azurerm_client_config.current.tenant_id
}

# Route Azure Monitor diagnostics to Log Analytics
resource "azurerm_monitor_diagnostic_setting" "kusto_to_logs" {
  name                       = "kusto-diagnostics-to-sre-agent"
  target_resource_id         = azurerm_kusto_cluster.main.id
  log_analytics_workspace_id = azurerm_log_analytics_workspace.sre_agent.id

  enabled_log {
    category = "SucceededIngestion"
  }

  enabled_log {
    category = "FailedIngestion"
  }

  enabled_log {
    category = "Command"
  }

  metric {
    category = "AllMetrics"
    enabled  = true
  }
}

# Action group for SRE incident notifications
resource "azurerm_monitor_action_group" "sre_incidents" {
  name                = "${var.sre_agent_name}-incidents"
  resource_group_name = data.azurerm_resource_group.main.name
  short_name          = "sre-inc"
  enabled             = true

  webhook_receiver {
    name                    = "sre-agent-webhook"
    service_uri             = "http://${azurerm_container_group.sre_agent.ip_address}:8080/api/incidents"
    use_common_alert_schema = true
  }

  tags = { Environment = "Production", Purpose = "SRE-Incident-Routing" }
}

