# Variables

variable "resource_group_name" {
  default = "RS_Hypera_Cafehyna"
}

variable "location" {
  default = "southcentralus"
}

variable "cluster_name" {
  default = "sre-kusto-hypera"
}

variable "database_name" {
  default = "hypera-pharma-sre"
}

variable "sre_principal_id" {
  default = "789b0076-450f-4aa2-99c1-7b2dfc14bc7f"
}

variable "sre_agent_name" {
  type    = string
  default = "sre-agent-hypera"
}

variable "sre_agent_container_image" {
  type    = string
  default = "ghcr.io/microsoft/sre-agent:latest"
}

variable "sre_agent_mcp_connectors" {
  type = map(object({
    endpoint       = string
    api_key_secret = string
  }))
  default = {}
}

variable "observability_providers" {
  type    = list(string)
  default = ["azure-monitor"]
}

variable "incident_management_provider" {
  type    = string
  default = "servicenow"
}

# Data source for resource group
data "azurerm_resource_group" "main" {
  name = var.resource_group_name
}

# Get current Azure context
data "azurerm_client_config" "current" {}

# Create Azure Data Explorer Cluster (Simplified - valid args only)
resource "azurerm_kusto_cluster" "main" {
  name                = var.cluster_name
  location            = data.azurerm_resource_group.main.location
  resource_group_name = data.azurerm_resource_group.main.name

  sku {
    name     = "Dev(No SLA)_Standard_E2a_v4"
    capacity = 1
  }

  tags = {
    Environment = "Production"
    Purpose     = "SRE-Logging"
  }
}

# Create Database
resource "azurerm_kusto_database" "main" {
  name                = var.database_name
  resource_group_name = data.azurerm_resource_group.main.name
  location            = data.azurerm_resource_group.main.location
  cluster_name        = azurerm_kusto_cluster.main.name

  soft_delete_period = "P365D"
  hot_cache_period   = "P31D"
}

# Grant SRE Agent Viewer Access
resource "azurerm_kusto_database_principal_assignment" "sre_agent" {
  resource_group_name = data.azurerm_resource_group.main.name
  cluster_name        = azurerm_kusto_cluster.main.name
  database_name       = azurerm_kusto_database.main.name
  name                = "sre-agent-viewer"
  principal_id        = var.sre_principal_id
  principal_type      = "App"
  role                = "Viewer"
  tenant_id           = data.azurerm_client_config.current.tenant_id
}
